        vector<string> answer(n+1, "");
        for (int i = 1; i <= n; i++) {
            if (i % 3 == 0 && i % 5 == 0) {
                answer[i] = to_string(i);
            } else if (i % 3 == 0) {
                answer[i] = "Fizz";
            } else if (i % 5 == 0) {
                answer[i] = "Buzz";
